#!/usr/bin/env php
<?php
declare(strict_types=1);
use App\Core\Env;use App\Core\Database;use App\Services\EmailService;
require dirname(__DIR__).'/app/core/Env.php';Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function($c){$p='App\\';if(!str_starts_with($c,$p))return;$relative=substr($c,strlen($p));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$f=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($f))require $f;});$v=dirname(__DIR__).'/vendor/autoload.php';if(is_file($v))require $v;
$pdo=Database::connection();$rows=$pdo->query("SELECT * FROM executive_report_schedules WHERE active=1 AND (next_run_at IS NULL OR next_run_at<=NOW())")->fetchAll();$mail=new EmailService();
foreach($rows as $s){$end=date('Y-m-d');$start=match($s['frequency']){'daily'=>$end,'monthly'=>date('Y-m-01'),default=>date('Y-m-d',strtotime('-6 days'))};try{$rev=$pdo->prepare('SELECT COALESCE(SUM(amount),0) FROM payments WHERE DATE(received_at) BETWEEN ? AND ?');$rev->execute([$start,$end]);$jobs=$pdo->prepare("SELECT COUNT(*) FROM jobs WHERE DATE(scheduled_start) BETWEEN ? AND ? AND status='completed'");$jobs->execute([$start,$end]);$open=(float)$pdo->query("SELECT COALESCE(SUM(balance_due),0) FROM invoices WHERE balance_due>0")->fetchColumn();$html='<h1>Rock Bluffs Executive Report</h1><p>Period: '.$start.' through '.$end.'</p><table border="1" cellpadding="8"><tr><th>Revenue received</th><td>$'.number_format((float)$rev->fetchColumn(),2).'</td></tr><tr><th>Completed jobs</th><td>'.(int)$jobs->fetchColumn().'</td></tr><tr><th>Open receivables</th><td>$'.number_format($open,2).'</td></tr></table>';$recipients=array_filter(array_map('trim',explode(',',$s['recipients'])));foreach($recipients as $to)$mail->sendMail($to,$s['name'].' - '.$end,$html);$pdo->prepare("INSERT INTO executive_report_runs(schedule_id,report_key,period_start,period_end,recipients,status,sent_at) VALUES(?,?,?,?,?,'sent',NOW())")->execute([$s['id'],$s['report_key'],$start,$end,$s['recipients']]);$next=match($s['frequency']){'daily'=>'+1 day','monthly'=>'+1 month',default=>'+1 week'};$pdo->prepare('UPDATE executive_report_schedules SET last_run_at=NOW(),next_run_at=? WHERE id=?')->execute([date('Y-m-d '.$s['send_time'],strtotime($next)),$s['id']]);}catch(Throwable $e){$pdo->prepare("INSERT INTO executive_report_runs(schedule_id,report_key,period_start,period_end,recipients,status,error_message) VALUES(?,?,?,?,?,'failed',?)")->execute([$s['id'],$s['report_key'],$start,$end,$s['recipients'],$e->getMessage()]);}}
echo 'Processed '.count($rows)." report schedule(s).\n";
